1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty grid when given empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with 0 neighbors", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should preserve a 2x2 block (still life - each cell has 3 neighbors)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
18	      new Set(["0,0", "1,0", "0,1", "1,1"]),
19	    );
20	  });
21	  it("should rotate a vertical blinker into a horizontal blinker", () => {
22	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
23	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
24	      new Set(["-1,1", "0,1", "1,1"]),
25	    );
26	  });
27	  it("should bring a dead cell with exactly 3 live neighbors to life", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
30	      new Set(["0,0", "1,0", "0,1", "1,1"]),
31	    );
32	  });
33	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
34	    // 2x3 block: cells (0,1) and (1,1) each have 5 live neighbors → die
35	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1], [0, 2], [1, 2]]);
36	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
37	      new Set(["0,0", "1,0", "0,2", "1,2", "-1,1", "2,1"]),
38	    );
39	  });
40	  it.todo("should support negative coordinates");
41	});
42

1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const neighborOffsets: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const neighborsOf = (x: number, y: number): Cell[] =>
12	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const cellAndNeighbors = (x: number, y: number): Cell[] =>
15	  [[x, y], ...neighborsOf(x, y)];
16	
17	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number =>
18	  neighborsOf(x, y).filter(([nx, ny]) => liveSet.has(cellKey(nx, ny))).length;
19	
20	const survives = (liveNeighbors: number): boolean =>
21	  liveNeighbors === 2 || liveNeighbors === 3;
22	
23	const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;
24	
25	const candidateCells = (cells: Cell[]): Map<string, Cell> => {
26	  const candidates = new Map<string, Cell>();
27	  for (const [x, y] of cells) {
28	    for (const [cx, cy] of cellAndNeighbors(x, y)) {
29	      candidates.set(cellKey(cx, cy), [cx, cy]);
30	    }
31	  }
32	  return candidates;
33	};
34	
35	export function nextGeneration(cells: Cell[]): Cell[] {
36	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
37	
38	  const result: Cell[] = [];
39	  for (const [key, [x, y]] of candidateCells(cells)) {
40	    const liveNeighbors = countLiveNeighbors(x, y, liveSet);
41	    const wasAlive = liveSet.has(key);
42	    if (wasAlive ? survives(liveNeighbors) : isBorn(liveNeighbors)) {
43	      result.push([x, y]);
44	    }
45	  }
46	  return result;
47	}
